@ApiTags('GitHub Integration')
@Controller('integrations/github')
export class GithubInstallController {
  // inject: GithubInstallService, EnvConfigService

  @Post('connect')
  @Roles('admin')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: 'Initiate GitHub App installation' })
  @ApiResponse({ status: HttpStatus.OK, description: 'Returns GitHub install URL' })
  @LogExecution()
  async connect(@CurrentUser() user: IRequestUser): Promise<{ url: string }>
  // calls githubInstallService.initiateConnect({ companyId: user.company_id!, userId: user.user_id })

  @Get('callback')
  @Roles('admin')
  @ApiOperation({ summary: 'GitHub App installation callback' })
  @ApiResponse({ status: HttpStatus.FOUND, description: 'Redirects to frontend' })
  @LogExecution()
  async callback(
    @Query() query: { installation_id: string; state: string; setup_action: string },
    @Res() reply: FastifyReply,
  ): Promise<void>
  // on success: redirect to `${frontendUrl}/settings/integrations?connected=github`
  // on any error: redirect to `${frontendUrl}/settings/integrations?error=github_connect_failed`
  // frontendUrl = configService.get<string>({ key: FRONTEND_URL })

  @Delete('installations/:id')
  @Roles('admin')
  @HttpCode(HttpStatus.NO_CONTENT)
  @ApiOperation({ summary: 'Disconnect GitHub installation' })
  @ApiResponse({ status: HttpStatus.NO_CONTENT, description: 'Installation disconnected' })
  @LogExecution()
  async disconnect(@Param() params: { id: string }, @CurrentUser() user: IRequestUser): Promise<void>
  // calls githubInstallService.disconnect({ installationDbId: params.id, companyId: user.company_id! })
}
