## Unit test for GithubInstallController

File: `src/unit-tests/github-install.controller.unit-spec.ts`

```typescript
import { BadRequestException, Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { IRequestUser } from '@modules/auth/types/auth.interface';
import { EnvConfigService } from '@modules/env-config/env-config.service';
import { GithubInstallController } from '@modules/github/github-install.controller';
import { GithubInstallService } from '@modules/github/github-install.service';
import {
  GithubInstallationStatus,
  IGithubInstallationBase,
} from '@modules/github/types/github-installation.interface';

import type { FastifyReply } from 'fastify';

const mockInstallation: IGithubInstallationBase = {
  _id: 'install-uuid-1',
  company_id: 'company-uuid-1',
  installation_id: 12345678,
  org_login: 'acme-corp',
  org_id: 987654,
  status: GithubInstallationStatus.ACTIVE,
  installed_at: new Date('2026-04-14'),
  suspended_at: null,
  uninstalled_at: null,
  created_at: new Date('2026-04-14'),
  updated_at: new Date('2026-04-14'),
};

const mockAdminUser: IRequestUser = {
  user_id: 'user-uuid-1',
  session_id: 'session-1',
  role: 'admin',
  company_id: 'company-uuid-1',
};

const mockInstallService = {
  initiateConnect: jest.fn(),
  handleCallback: jest.fn(),
  disconnect: jest.fn(),
};

const mockConfigService = {
  get: jest.fn().mockReturnValue('http://localhost:3000'),
};

describe('GithubInstallController', () => {
  let controller: GithubInstallController;

  beforeEach(async () => {
    jest.clearAllMocks();

    const module: TestingModule = await Test.createTestingModule({
      controllers: [GithubInstallController],
      providers: [
        { provide: GithubInstallService, useValue: mockInstallService },
        { provide: EnvConfigService, useValue: mockConfigService },
      ],
    }).compile();

    controller = module.get<GithubInstallController>(GithubInstallController);

    jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
    jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
  });

  afterEach(() => jest.clearAllMocks());

  it('should be defined', () => {
    expect(controller).toBeDefined();
  });

  describe('connect', () => {
    it('should return redirect URL from service', async () => {
      const url = 'https://github.com/apps/my-app/installations/new?state=abc';
      mockInstallService.initiateConnect.mockResolvedValue(url);

      const result = await controller.connect(mockAdminUser);

      expect(mockInstallService.initiateConnect).toHaveBeenCalledWith({
        companyId: mockAdminUser.company_id,
        userId: mockAdminUser.user_id,
      });
      expect(result).toEqual({ url });
    });
  });

  describe('callback', () => {
    it('should handle callback and redirect to frontend on success', async () => {
      mockInstallService.handleCallback.mockResolvedValue(mockInstallation);
      const mockReply = { redirect: jest.fn() };

      await controller.callback(
        { installation_id: '12345678', state: 'abc123', setup_action: 'install' },
        mockReply as unknown as FastifyReply,
      );

      expect(mockInstallService.handleCallback).toHaveBeenCalledWith({
        installationId: 12345678,
        state: 'abc123',
      });
      expect(mockReply.redirect).toHaveBeenCalledWith(
        expect.stringContaining('/settings/integrations'),
      );
    });

    it('should redirect to error page on BadRequestException', async () => {
      mockInstallService.handleCallback.mockRejectedValue(
        new BadRequestException('Invalid state'),
      );
      const mockReply = { redirect: jest.fn() };

      await controller.callback(
        { installation_id: '12345678', state: 'bad', setup_action: 'install' },
        mockReply as unknown as FastifyReply,
      );

      expect(mockReply.redirect).toHaveBeenCalledWith(
        expect.stringContaining('/settings/integrations?error='),
      );
    });
  });

  describe('disconnect', () => {
    it('should call service disconnect with correct params', async () => {
      mockInstallService.disconnect.mockResolvedValue(undefined);

      await controller.disconnect({ id: 'install-uuid-1' }, mockAdminUser);

      expect(mockInstallService.disconnect).toHaveBeenCalledWith({
        installationDbId: 'install-uuid-1',
        companyId: mockAdminUser.company_id,
      });
    });
  });
});
```

## Unit test for GithubWebhookController

File: `src/unit-tests/github-webhook.controller.unit-spec.ts`

```typescript
import { Logger, UnauthorizedException } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { GithubWebhookController } from '@modules/github/github-webhook.controller';
import { GithubWebhookService } from '@modules/github/github-webhook.service';

const mockWebhookService = {
  verifySignature: jest.fn(),
  handleEvent: jest.fn(),
};

describe('GithubWebhookController', () => {
  let controller: GithubWebhookController;

  beforeEach(async () => {
    jest.clearAllMocks();

    const module: TestingModule = await Test.createTestingModule({
      controllers: [GithubWebhookController],
      providers: [{ provide: GithubWebhookService, useValue: mockWebhookService }],
    }).compile();

    controller = module.get<GithubWebhookController>(GithubWebhookController);

    jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
    jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
    jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
  });

  afterEach(() => jest.clearAllMocks());

  it('should be defined', () => {
    expect(controller).toBeDefined();
  });

  describe('handleWebhook', () => {
    it('should throw UnauthorizedException when signature is invalid', async () => {
      mockWebhookService.verifySignature.mockReturnValue(false);

      await expect(
        controller.handleWebhook(
          {
            'x-github-event': 'push',
            'x-hub-signature-256': 'sha256=invalid',
            'x-github-hook-installation-target-id': '12345678',
          },
          '{"ref":"refs/heads/main"}',
        ),
      ).rejects.toThrow(UnauthorizedException);
    });

    it('should call handleEvent when signature is valid', async () => {
      mockWebhookService.verifySignature.mockReturnValue(true);
      mockWebhookService.handleEvent.mockResolvedValue(undefined);

      await controller.handleWebhook(
        {
          'x-github-event': 'push',
          'x-hub-signature-256': 'sha256=valid',
          'x-github-hook-installation-target-id': '12345678',
        },
        '{"ref":"refs/heads/main"}',
      );

      expect(mockWebhookService.handleEvent).toHaveBeenCalledWith({
        event: 'push',
        installationId: 12345678,
        payload: { ref: 'refs/heads/main' },
      });
    });
  });
});
```

