18	const DEFAULT_SENSITIVE_KEYS: string[] = [
19		'password',
20		'pass',
21		'token',
22		'secret',
23		'auth',
24		'authorization',
25		'cookie',
26		'session',
27		'credentials',
28		'apiKey',
29		'csrf',
