42			event,
43			installationId,
44			payload,
45		}: {
46			event: string;
47			installationId: number;
48			payload: unknown;
49		}): Promise<void> {
50			const installation = await this.githubInstallationModel.findByInstallationId({
51				installationId,
52			});
53	
54			if (!installation) {
55				this.logger.warn(`Webhook received for unknown installation: ${installationId}`);
56				return;
57			}
58	
59			if (installation.status === GithubInstallationStatus.UNINSTALLED) {
60				this.logger.warn(`Webhook received for uninstalled installation: ${installationId}`);
61				return;
62			}
63	
64			if (event === 'installation') {
65				await this.handleInstallationLifecycle({
66					installationId,
67					payload: payload as IGithubInstallationEvent,
68				});
69				return;
70			}
71	
72			if (installation.status === GithubInstallationStatus.SUSPENDED) {
73				this.logger.warn(`Dropping event for suspended installation: ${installationId}`);
74				return;
75			}
76	
77			await this.githubQueue.add('raw_event', {
78				event,
79				installationId,
80				payload,
81				receivedAt: new Date(),
82			});
83	
84			this.logger.debug(`Queued ${event} event for installation ${installationId}`);
85		}
